/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Keyboard Shortcuts Help Overlay
   Dark glass modal showing all available keyboard shortcuts by category.
   Triggered by pressing ? or Ctrl+/ when not in an input field.
   Built on Radix Dialog + Framer Motion. Matches CommandPalette design.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useEffect } from 'react';
import * as Dialog from '@radix-ui/react-dialog';
import { motion, AnimatePresence } from 'framer-motion';
import { useTheme } from '../contexts/ThemeContext';

const FALLBACK = {
  bg: '#0B0F14', surface: '#0F1620', surface2: '#111A24',
  border: '#1F2A37', textPrimary: '#E5E7DB', textSecondary: '#90A3AF',
  blue: '#60A5FA', amber: '#F59E0B', green: '#22C55E',
  red: '#EF4444', purple: '#A78BFA',
};

/* ── Shortcut data ────────────────────────────────────────────────────────── */
const SHORTCUT_GROUPS = [
  {
    title: 'Navigation',
    color: '#60A5FA',
    shortcuts: [
      { keys: ['\u2318', 'K'], label: 'Command palette' },
      { keys: ['\u2318', '1\u20135'], label: 'Switch domain tabs' },
      { keys: ['G', 'then', 'H'], label: 'Go to Home' },
      { keys: ['G', 'then', 'S'], label: 'Go to Strategies' },
      { keys: ['G', 'then', 'C'], label: 'Go to Charts' },
      { keys: ['G', 'then', 'P'], label: 'Go to Positions' },
      { keys: ['G', 'then', 'A'], label: 'Go to Alerts' },
      { keys: ['G', 'then', 'N'], label: 'Go to Signals' },
    ],
  },
  {
    title: 'Trading',
    color: '#EF4444',
    shortcuts: [
      { keys: ['\u2318', 'N'], label: 'New chart panel' },
      { keys: ['\u2318', 'B'], label: 'Bot command' },
      { keys: ['Ctrl', 'Shift', 'K'], label: 'Kill switch (with confirm)' },
    ],
  },
  {
    title: 'General',
    color: '#22C55E',
    shortcuts: [
      { keys: ['?'], label: 'Show this help' },
      { keys: ['Esc'], label: 'Close any modal / overlay' },
      { keys: ['\u2318', ','], label: 'Settings' },
    ],
  },
];

/* ── Framer Motion variants ───────────────────────────────────────────────── */
const overlayV = {
  hidden: { opacity: 0 },
  visible: { opacity: 1 },
  exit: { opacity: 0 },
};
const modalV = {
  hidden: { opacity: 0, scale: 0.95, y: -20 },
  visible: {
    opacity: 1, scale: 1, y: 0,
    transition: { type: 'spring', damping: 28, stiffness: 400, mass: 0.8 },
  },
  exit: { opacity: 0, scale: 0.97, y: -10, transition: { duration: 0.15 } },
};

/* ── Kbd badge ────────────────────────────────────────────────────────────── */
function Kbd({ children, color }) {
  return (
    <kbd style={{
      display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
      minWidth: 24, height: 24, padding: '0 6px',
      fontSize: 11, fontWeight: 600,
      fontFamily: "'JetBrains Mono', monospace",
      background: 'rgba(255,255,255,0.06)',
      border: '1px solid rgba(255,255,255,0.1)',
      borderRadius: 6, color: color || '#E5E7DB',
      lineHeight: '22px',
      boxShadow: '0 1px 2px rgba(0,0,0,0.3), 0 1px 0 rgba(255,255,255,0.03) inset',
    }}>
      {children}
    </kbd>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════ */
export default function KeyboardShortcutsHelp({ open, onClose }) {
  const themeCtx = useTheme();
  const C = themeCtx?.colors || FALLBACK;

  // Detect Mac for displaying correct modifier key
  const isMac = typeof navigator !== 'undefined' && /Mac|iPod|iPhone|iPad/.test(navigator.platform);

  // Replace command symbol with Ctrl on non-Mac platforms
  const renderKey = (k) => (k === '\u2318' ? (isMac ? '\u2318' : 'Ctrl') : k);

  // Close on Ctrl+/ as well (mirrors the open shortcut)
  useEffect(() => {
    if (!open) return;
    const handler = (e) => {
      if ((e.ctrlKey || e.metaKey) && e.key === '/') {
        e.preventDefault();
        onClose();
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [open, onClose]);

  return (
    <Dialog.Root open={open} onOpenChange={(v) => { if (!v) onClose(); }}>
      <AnimatePresence>
        {open && (
          <Dialog.Portal forceMount>
            <Dialog.Overlay asChild>
              <motion.div
                variants={overlayV}
                initial="hidden"
                animate="visible"
                exit="exit"
                style={{
                  position: 'fixed', inset: 0, zIndex: 9998,
                  background: 'rgba(0,0,0,0.6)',
                  backdropFilter: 'blur(8px) saturate(120%)',
                  WebkitBackdropFilter: 'blur(8px) saturate(120%)',
                }}
              />
            </Dialog.Overlay>
            <Dialog.Content asChild onOpenAutoFocus={(e) => e.preventDefault()}>
              <motion.div
                variants={modalV}
                initial="hidden"
                animate="visible"
                exit="exit"
                style={{
                  position: 'fixed', top: '50%', left: '50%',
                  transform: 'translate(-50%, -50%)',
                  zIndex: 9999,
                  width: 'min(720px, 92vw)',
                  maxHeight: '80vh',
                  background: C.surface || FALLBACK.surface,
                  border: `1px solid ${C.border || FALLBACK.border}`,
                  borderRadius: 16,
                  overflow: 'hidden',
                  boxShadow: '0 32px 80px rgba(0,0,0,0.6), 0 0 0 1px rgba(255,255,255,0.03) inset',
                  display: 'flex', flexDirection: 'column',
                }}
              >
                {/* ── Header ── */}
                <div style={{
                  display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                  padding: '20px 24px 16px',
                  borderBottom: `1px solid ${C.border || FALLBACK.border}`,
                }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none"
                      stroke={C.blue || FALLBACK.blue} strokeWidth="1.8"
                      strokeLinecap="round" strokeLinejoin="round">
                      <rect x="2" y="6" width="20" height="12" rx="2" />
                      <path d="M6 10h.01M10 10h.01M14 10h.01M18 10h.01M8 14h8" />
                    </svg>
                    <Dialog.Title style={{
                      margin: 0, fontSize: 16, fontWeight: 700,
                      color: C.textPrimary || FALLBACK.textPrimary,
                      fontFamily: "'Plus Jakarta Sans', 'Inter', system-ui, sans-serif",
                      letterSpacing: '-0.01em',
                    }}>
                      Keyboard Shortcuts
                    </Dialog.Title>
                  </div>
                  <Dialog.Close asChild>
                    <button
                      aria-label="Close"
                      style={{
                        background: 'none', border: 'none', cursor: 'pointer',
                        color: C.textSecondary || FALLBACK.textSecondary,
                        padding: 4, borderRadius: 6, display: 'flex',
                        transition: 'color 0.15s, background 0.15s',
                      }}
                      onMouseEnter={(e) => {
                        e.currentTarget.style.color = C.textPrimary || FALLBACK.textPrimary;
                        e.currentTarget.style.background = 'rgba(255,255,255,0.06)';
                      }}
                      onMouseLeave={(e) => {
                        e.currentTarget.style.color = C.textSecondary || FALLBACK.textSecondary;
                        e.currentTarget.style.background = 'none';
                      }}
                    >
                      <svg width="18" height="18" viewBox="0 0 18 18" fill="none"
                        stroke="currentColor" strokeWidth="1.8" strokeLinecap="round">
                        <line x1="4" y1="4" x2="14" y2="14" />
                        <line x1="14" y1="4" x2="4" y2="14" />
                      </svg>
                    </button>
                  </Dialog.Close>
                </div>

                {/* ── Body — shortcut groups in responsive columns ── */}
                <div style={{
                  padding: '20px 24px 24px',
                  overflowY: 'auto',
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                  gap: '24px 32px',
                }}>
                  {SHORTCUT_GROUPS.map((group) => (
                    <div key={group.title}>
                      <div style={{
                        fontSize: 10, fontWeight: 700, letterSpacing: '0.08em',
                        textTransform: 'uppercase',
                        color: group.color,
                        marginBottom: 12,
                        fontFamily: "'JetBrains Mono', monospace",
                      }}>
                        {group.title}
                      </div>
                      <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                        {group.shortcuts.map((sc) => (
                          <div
                            key={sc.label}
                            style={{
                              display: 'flex', alignItems: 'center',
                              justifyContent: 'space-between',
                              padding: '7px 10px',
                              borderRadius: 8,
                              background: 'rgba(255,255,255,0.02)',
                              transition: 'background 0.1s',
                            }}
                            onMouseEnter={(e) => { e.currentTarget.style.background = 'rgba(255,255,255,0.04)'; }}
                            onMouseLeave={(e) => { e.currentTarget.style.background = 'rgba(255,255,255,0.02)'; }}
                          >
                            {/* Key combo */}
                            <span style={{ display: 'flex', alignItems: 'center', gap: 4, flexShrink: 0 }}>
                              {sc.keys.map((k, i) => (
                                k === 'then' ? (
                                  <span key={i} style={{
                                    fontSize: 10, color: 'rgba(255,255,255,0.25)',
                                    fontStyle: 'italic', margin: '0 1px',
                                    fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
                                  }}>
                                    then
                                  </span>
                                ) : (
                                  <Kbd key={i} color={group.color}>{renderKey(k)}</Kbd>
                                )
                              ))}
                            </span>
                            {/* Label */}
                            <span style={{
                              fontSize: 13, color: C.textSecondary || FALLBACK.textSecondary,
                              fontFamily: "'Plus Jakarta Sans', 'Inter', system-ui, sans-serif",
                              whiteSpace: 'nowrap', marginLeft: 12,
                            }}>
                              {sc.label}
                            </span>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>

                {/* ── Footer ── */}
                <div style={{
                  padding: '12px 24px',
                  borderTop: `1px solid ${C.border || FALLBACK.border}`,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  gap: 6, userSelect: 'none',
                }}>
                  <span style={{
                    fontSize: 11, color: C.textSecondary || FALLBACK.textSecondary,
                    opacity: 0.6,
                    fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
                  }}>
                    Press
                  </span>
                  <Kbd color={C.blue || FALLBACK.blue}>?</Kbd>
                  <span style={{
                    fontSize: 11, color: C.textSecondary || FALLBACK.textSecondary,
                    opacity: 0.6,
                    fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
                  }}>
                    or
                  </span>
                  <Kbd color={C.blue || FALLBACK.blue}>Esc</Kbd>
                  <span style={{
                    fontSize: 11, color: C.textSecondary || FALLBACK.textSecondary,
                    opacity: 0.6,
                    fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
                  }}>
                    to close
                  </span>
                </div>
              </motion.div>
            </Dialog.Content>
          </Dialog.Portal>
        )}
      </AnimatePresence>
    </Dialog.Root>
  );
}
